"""Прямоугольный сигнал (меандр)."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _check_below_nyquist, _time_axisclass SquareSignal(BaseSignal):    name = "Прямоугольный сигнал"    description = "Меандр амплитуды ±A с частотой f и коэффициентом заполнения duty."    params_schema = {        "amplitude": {"type": "float", "default": 1.0, "min": 0.0, "max": 1.0e6,                      "label": "Амплитуда", "units": "В"},        "frequency": {"type": "float", "default": 5.0, "min": 1.0e-6, "max": 1.0e6,                      "label": "Частота", "units": "Гц"},        "duty":      {"type": "float", "default": 0.5, "min": 0.01, "max": 0.99,                      "label": "Скважность"},        "duration":  {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                      "label": "Длительность", "units": "с"},        "fs":        {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                      "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        _check_below_nyquist("frequency", p["frequency"], p["fs"])        t = _time_axis(p["duration"], p["fs"])        phase = (p["frequency"] * t) % 1.0        x = np.where(phase < p["duty"], p["amplitude"], -p["amplitude"]).astype(np.float64)        return t, x